field.expresion:
@fan1 := (SELECT group_concat( ctafan separator '<br>')  FROM CCTCUENT  where
                        (concat(replace(ctatel, ' ',''), replace(ctafax, ' ',''))  like CONCAT('%' ,right(trim(numero), 6) ,'%') and trim(numero) != '' )  and
                        baja = 0 and length(trim(numero)) > 3 )

@emp := (SELECT CONCAT(Nombre, ' ', apellido) from HTXUSERS where
                        (replace(HTXUSERS.telefono, ' ','') like CONCAT('%' ,trim(entrantes) ,'%') and trim( entrantes) != '' )  or
                        (replace(HTXUSERS.telefono, ' ','') like CONCAT('%' ,trim(salientes) ,'%') and trim( salientes) != '' ) limit 1)
